import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { toast } from 'react-toastify';

// ── Auth Modal ───────────────────────────────────────────────────
function AuthModal({ onClose }) {
  const { login, register } = useAuth();
  const navigate = useNavigate();
  const [tab, setTab] = useState('login');
  const [loading, setLoading] = useState(false);
  const [loginForm, setLoginForm] = useState({ email: '', password: '' });
  const [regForm, setRegForm] = useState({
    name: '', email: '', password: '', role: 'patient',
    phone: '', age: '', gender: '', bloodGroup: '',
    specialization: '', licenseNumber: '',
  });

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const user = await login(loginForm.email, loginForm.password);
      toast.success(`Welcome back, ${user.name}`);
      onClose();
      navigate('/app/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally { setLoading(false); }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await register(regForm);
      toast.success('Account created successfully');
      onClose();
      navigate('/app/dashboard');
    } catch (err) {
      toast.error(err.response?.data?.errors?.[0]?.msg || err.response?.data?.message || 'Registration failed');
    } finally { setLoading(false); }
  };

  return (
    <div className="ehr-modal-overlay" onClick={onClose}>
      <div className="ehr-modal" style={{ maxWidth: 480 }} onClick={e => e.stopPropagation()}>
        <div className="ehr-modal-header">
          <span className="ehr-modal-title">
            <i className="bi bi-heart-pulse-fill me-2" style={{ color: '#ef4444' }} />
            MediCare EHR
          </span>
          <button className="ehr-modal-close" onClick={onClose}><i className="bi bi-x" /></button>
        </div>

        {/* Tabs */}
        <div style={{ display: 'flex', borderBottom: '1px solid var(--border)', background: 'var(--bg)' }}>
          {['login', 'register'].map(t => (
            <button key={t} onClick={() => setTab(t)} style={{
              flex: 1, padding: '0.75rem', border: 'none', background: 'none', cursor: 'pointer',
              fontWeight: 600, fontSize: '0.875rem',
              color: tab === t ? 'var(--primary)' : 'var(--text-muted)',
              borderBottom: tab === t ? '2px solid var(--primary)' : '2px solid transparent',
              transition: 'all 0.18s',
            }}>
              {t === 'login' ? 'Sign In' : 'Create Account'}
            </button>
          ))}
        </div>

        <div className="ehr-modal-body">
          {tab === 'login' ? (
            <form onSubmit={handleLogin}>
              <div className="mb-3">
                <label className="form-label">Email Address</label>
                <input type="email" className="form-control" placeholder="you@example.com" required
                  value={loginForm.email} onChange={e => setLoginForm(f => ({ ...f, email: e.target.value }))} />
              </div>
              <div className="mb-4">
                <label className="form-label">Password</label>
                <input type="password" className="form-control" placeholder="••••••••" required
                  value={loginForm.password} onChange={e => setLoginForm(f => ({ ...f, password: e.target.value }))} />
              </div>
              <button type="submit" className="btn btn-primary w-100 py-2" disabled={loading}>
                {loading ? <><span className="spinner-border spinner-border-sm me-2" />Signing in...</> : <><i className="bi bi-box-arrow-in-right me-2" />Sign In</>}
              </button>
            </form>
          ) : (
            <form onSubmit={handleRegister}>
              <div className="d-flex gap-2 mb-3">
                {['patient', 'doctor'].map(r => (
                  <button key={r} type="button" onClick={() => setRegForm(f => ({ ...f, role: r }))}
                    style={{
                      flex: 1, padding: '0.6rem', border: `2px solid ${regForm.role === r ? 'var(--primary)' : 'var(--border)'}`,
                      borderRadius: 8, background: regForm.role === r ? 'var(--primary-light)' : 'var(--surface)',
                      color: regForm.role === r ? 'var(--primary)' : 'var(--text-muted)',
                      fontWeight: 600, fontSize: '0.875rem', cursor: 'pointer',
                    }}>
                    <i className={`bi ${r === 'patient' ? 'bi-person' : 'bi-person-badge'} me-1`} />
                    {r.charAt(0).toUpperCase() + r.slice(1)}
                  </button>
                ))}
              </div>
              <div className="row g-2">
                <div className="col-6">
                  <label className="form-label">Full Name *</label>
                  <input className="form-control" required placeholder="John Doe"
                    value={regForm.name} onChange={e => setRegForm(f => ({ ...f, name: e.target.value }))} />
                </div>
                <div className="col-6">
                  <label className="form-label">Email *</label>
                  <input type="email" className="form-control" required placeholder="you@example.com"
                    value={regForm.email} onChange={e => setRegForm(f => ({ ...f, email: e.target.value }))} />
                </div>
                <div className="col-6">
                  <label className="form-label">Password *</label>
                  <input type="password" className="form-control" required minLength={6} placeholder="Min. 6 chars"
                    value={regForm.password} onChange={e => setRegForm(f => ({ ...f, password: e.target.value }))} />
                </div>
                <div className="col-6">
                  <label className="form-label">Phone</label>
                  <input className="form-control" placeholder="+91 XXXXX XXXXX"
                    value={regForm.phone} onChange={e => setRegForm(f => ({ ...f, phone: e.target.value }))} />
                </div>
                {regForm.role === 'patient' && (
                  <>
                    <div className="col-4">
                      <label className="form-label">Age</label>
                      <input type="number" className="form-control" placeholder="25"
                        value={regForm.age} onChange={e => setRegForm(f => ({ ...f, age: e.target.value }))} />
                    </div>
                    <div className="col-4">
                      <label className="form-label">Gender</label>
                      <select className="form-select" value={regForm.gender} onChange={e => setRegForm(f => ({ ...f, gender: e.target.value }))}>
                        <option value="">Select</option>
                        <option value="male">Male</option>
                        <option value="female">Female</option>
                        <option value="other">Other</option>
                      </select>
                    </div>
                    <div className="col-4">
                      <label className="form-label">Blood Group</label>
                      <select className="form-select" value={regForm.bloodGroup} onChange={e => setRegForm(f => ({ ...f, bloodGroup: e.target.value }))}>
                        <option value="">Select</option>
                        {['A+','A-','B+','B-','AB+','AB-','O+','O-'].map(g => <option key={g}>{g}</option>)}
                      </select>
                    </div>
                  </>
                )}
                {regForm.role === 'doctor' && (
                  <>
                    <div className="col-6">
                      <label className="form-label">Specialization</label>
                      <input className="form-control" placeholder="e.g. Cardiology"
                        value={regForm.specialization} onChange={e => setRegForm(f => ({ ...f, specialization: e.target.value }))} />
                    </div>
                    <div className="col-6">
                      <label className="form-label">License No.</label>
                      <input className="form-control" placeholder="LIC-XXXXXX"
                        value={regForm.licenseNumber} onChange={e => setRegForm(f => ({ ...f, licenseNumber: e.target.value }))} />
                    </div>
                  </>
                )}
              </div>
              <button type="submit" className="btn btn-primary w-100 py-2 mt-3" disabled={loading}>
                {loading ? <><span className="spinner-border spinner-border-sm me-2" />Creating...</> : <><i className="bi bi-person-plus me-2" />Create Account</>}
              </button>
            </form>
          )}
        </div>
      </div>
    </div>
  );
}
